1	import { create } from 'zustand';
2	
3	import type {
4	  Element,
5	  EvidenceRef,
6	  EvidenceRefKind,
7	  PerspectiveId,
8	  Violation,
9	  WorkspaceLayoutPreset,
10	  XY,
11	} from '@bim-ai/core';
12	
13	import type { PlanPresentationPreset } from '../plan/symbology';
14	
15	import type { StoreState } from './storeTypes';
16	
17	export type {
18	  PlanRoomSchemeWireReadout,
19	  ViewerMode,
20	  PlanTool,
21	  PresencePeers,
22	  UxComment,
23	  ActivityEvent,
24	  CategoryOverride,
25	  CategoryOverrides,
26	} from './storeTypes';
27	
28	function coerceViolation(v: unknown): Violation {
29	  const vv = v as Record<string, unknown>;
30	  const ruleId =
31	    typeof vv.ruleId === 'string' ? vv.ruleId : typeof vv.rule_id === 'string' ? vv.rule_id : '';
32	  const sev = vv.severity as string | undefined;
33	  const severity =
34	    sev === 'error' || sev === 'warning' || sev === 'info' ? sev : ('warning' as const);
35	  const elementIdsRaw = vv.elementIds ?? vv.element_ids;
36	  const elementIds =
37	    Array.isArray(elementIdsRaw) && elementIdsRaw.every((x) => typeof x === 'string')
38	      ? elementIdsRaw
39	      : [];
40	  const message = typeof vv.message === 'string' ? vv.message : '';
41	  const blocking = typeof vv.blocking === 'boolean' ? vv.blocking : undefined;
42	  const disciplineRaw = vv.discipline ?? vv.Discipline;
43	  const discipline =
44	    typeof disciplineRaw === 'string' && disciplineRaw.length ? disciplineRaw : undefined;
45	  const qf = vv.quickFixCommand ?? vv.quick_fix_command;
46	
47	  const quickFixCommand =
48	    qf !== undefined && qf !== null && typeof qf === 'object'
49	      ? (qf as Record<string, unknown>)
50	      : null;
51	
52	  return {
53	    ruleId,
54	    severity: severity as Violation['severity'],
55	    message,
56	    elementIds,
57	
58	    ...(blocking !== undefined ? { blocking } : {}),
59	
60	    ...(discipline !== undefined ? { discipline } : {}),
61	
62	    ...(quickFixCommand ? { quickFixCommand } : {}),
63	  };
64	}
65	
66	function coerceXY(raw: Record<string, unknown>): { xMm: number; yMm: number } {
67	  return {
68	    xMm: Number(raw.xMm ?? raw.x_mm ?? 0),
69	    yMm: Number(raw.yMm ?? raw.y_mm ?? 0),
70	  };
71	}
72	
73	function coerceXYZ(raw: Record<string, unknown>): { xMm: number; yMm: number; zMm: number } {
74	  return {
75	    xMm: Number(raw.xMm ?? raw.x_mm ?? 0),
76	    yMm: Number(raw.yMm ?? raw.y_mm ?? 0),
77	    zMm: Number(raw.zMm ?? raw.z_mm ?? 0),
78	  };
79	}
80	
81	const _EVIDENCE_REF_KINDS = new Set<EvidenceRefKind>([
82	  'sheet',
83	  'viewpoint',
84	  'plan_view',
85	  'section_cut',
86	  'deterministic_png',
87	]);
88	
89	function coerceEvidenceRefs(rawUnknown: unknown): EvidenceRef[] {
90	  if (!Array.isArray(rawUnknown)) return [];
91	  const refs: EvidenceRef[] = [];
92	  for (const item of rawUnknown) {
93	    if (typeof item !== 'object' || item === null) continue;
94	    const o = item as Record<string, unknown>;
95	    const kindRaw = o.kind;
96	    if (typeof kindRaw !== 'string' || !_EVIDENCE_REF_KINDS.has(kindRaw as EvidenceRefKind)) {
97	      continue;
98	    }
99	    const kind = kindRaw as EvidenceRefKind;
100	    const sheetId =
101	      typeof (o.sheetId ?? o.sheet_id) === 'string' ? String(o.sheetId ?? o.sheet_id) : undefined;
102	    const viewpointId =
103	      typeof (o.viewpointId ?? o.viewpoint_id) === 'string'
104	        ? String(o.viewpointId ?? o.viewpoint_id)
105	        : undefined;
106	    const planViewId =
107	      typeof (o.planViewId ?? o.plan_view_id) === 'string'
108	        ? String(o.planViewId ?? o.plan_view_id)
109	        : undefined;
110	    const sectionCutId =
111	      typeof (o.sectionCutId ?? o.section_cut_id) === 'string'
112	        ? String(o.sectionCutId ?? o.section_cut_id)
113	        : undefined;
114	    const pngBasename =
115	      typeof (o.pngBasename ?? o.png_basename) === 'string'
116	        ? String(o.pngBasename ?? o.png_basename)
117	        : undefined;
118	    refs.push({
