437	/** Editable inspector for plan_view elements (Properties tab). */
438	export function InspectorPlanViewEditor({
439	  el,
440	  elementsById,
441	  revision,
442	  onPersistProperty,
443	}: {
444	  el: Extract<Element, { kind: 'plan_view' }>;
445	  elementsById: Record<string, Element>;
446	  revision: number;
447	  onPersistProperty: (key: string, value: string) => void;
448	}): JSX.Element {
449	  const levels = (Object.values(elementsById) as Element[]).filter(
450	    (e): e is Extract<Element, { kind: 'level' }> => e.kind === 'level',
451	  );
452	  const templates = (Object.values(elementsById) as Element[]).filter(
453	    (e): e is Extract<Element, { kind: 'view_template' }> => e.kind === 'view_template',
454	  );
455	
456	  const { t } = useTranslation();
457	  const pv = (key: string) => t(`inspector.planView.${key}`);
458	
459	  const [cropDraft, setCropDraft] = useState({
460	    minX: el.cropMinMm ? String(el.cropMinMm.xMm) : '',
461	    minY: el.cropMinMm ? String(el.cropMinMm.yMm) : '',
462	    maxX: el.cropMaxMm ? String(el.cropMaxMm.xMm) : '',
463	    maxY: el.cropMaxMm ? String(el.cropMaxMm.yMm) : '',
464	  });
465	
466	  return (
467	    <div className="space-y-2 text-[11px]">
468	      <label className={LABEL_CLS}>
469	        {pv('namePlaceholder')}
470	        <input
471	          className={INPUT_CLS}
472	          defaultValue={el.name}
473	          key={`pv-name-${el.id}-${el.name}-${revision}`}
474	          onBlur={(e) => {
475	            const v = e.target.value.trim();
476	            if (!v || v === el.name) return;
477	            onPersistProperty('name', v);
478	          }}
479	        />
480	      </label>
481	
482	      <label className={LABEL_CLS}>
483	        {pv('planPresentation')}
484	        <select
485	          className={INPUT_CLS}
486	          value={el.planPresentation ?? 'default'}
487	          onChange={(e) => onPersistProperty('planPresentation', e.target.value)}
488	        >
489	          <option value="default">{pv('neutralPresentation')}</option>
490	          <option value="opening_focus">{pv('openingFocus')}</option>
491	          <option value="room_scheme">{pv('roomScheme')}</option>
492	        </select>
493	      </label>
494	
495	      <label className={LABEL_CLS}>
496	        {pv('underlayLevel')}
497	        <select
498	          className={INPUT_CLS}
499	          value={
500	            el.underlayLevelId && levels.some((l) => l.id === el.underlayLevelId)
501	              ? el.underlayLevelId
502	              : ''
503	          }
504	          onChange={(e) => onPersistProperty('underlayLevelId', e.target.value)}
505	        >
506	          <option value="">{pv('none')}</option>
507	          {levels.map((l) => (
508	            <option key={l.id} value={l.id}>
509	              {l.name}
510	            </option>
511	          ))}
512	        </select>
513	      </label>
514	
515	      {templates.length > 0 ? (
516	        <>
517	          <label className={LABEL_CLS}>
518	            {pv('viewTemplateLink')}
519	            <select
520	              className={INPUT_CLS}
521	              value={
522	                el.viewTemplateId && templates.some((tmpl) => tmpl.id === el.viewTemplateId)
523	                  ? el.viewTemplateId
524	                  : ''
525	              }
526	              onChange={(e) => onPersistProperty('viewTemplateId', e.target.value)}
527	            >
528	              <option value="">{pv('none')}</option>
529	              {templates.map((tmpl) => (
530	                <option key={tmpl.id} value={tmpl.id}>
531	                  {tmpl.name}
532	                </option>
533	              ))}
534	            </select>
535	          </label>
536	          <label className={LABEL_CLS}>
537	            {pv('applyTemplate')}
538	            <select
539	              className={INPUT_CLS}
540	              value=""
541	              onChange={(e) => {
542	                const tid = e.target.value;
543	                if (!tid) return;
544	                onPersistProperty(
545	                  '__applyTemplate__',
546	                  JSON.stringify({ planViewId: el.id, templateId: tid }),
547	                );
548	              }}
549	            >
550	              <option value="">{pv('selectToApply')}</option>
551	              {templates.map((tmpl) => (
552	                <option key={tmpl.id} value={tmpl.id}>
553	                  {tmpl.name}
554	                </option>
555	              ))}
556	            </select>
557	          </label>
558	        </>
559	      ) : null}
560	
561	      <div className="border-t border-border pt-2 space-y-2">
562	        <div className="font-semibold text-muted">{pv('crop')}</div>
563	        <div className="grid grid-cols-2 gap-2">
564	          {(['minX', 'minY', 'maxX', 'maxY'] as const).map((k) => (
565	            <label key={k} className={LABEL_CLS}>
566	              {k}
567	              <input
568	                className={INPUT_CLS}
569	                value={cropDraft[k]}
570	                onChange={(e) => setCropDraft((d) => ({ ...d, [k]: e.target.value }))}
571	              />
572	            </label>
573	          ))}
574	        </div>
575	        <div className="flex gap-2">
576	          <button
577	            type="button"
578	            className="flex-1 rounded border border-border bg-background px-2 py-1 text-[10px] hover:bg-surface-strong"
579	            onClick={() => {
580	              const nx = Number(cropDraft.minX),
581	                ny = Number(cropDraft.minY);
582	              const xx = Number(cropDraft.maxX),
583	                xy = Number(cropDraft.maxY);
584	              if (![nx, ny, xx, xy].every(Number.isFinite)) return;
585	              onPersistProperty('cropMinMm', JSON.stringify({ xMm: nx, yMm: ny }));
586	              onPersistProperty('cropMaxMm', JSON.stringify({ xMm: xx, yMm: xy }));
587	            }}
588	          >
589	            {pv('applyCrop')}
590	          </button>
591	          <button
592	            type="button"
593	            className="flex-1 rounded border border-border bg-background px-2 py-1 text-[10px] hover:bg-surface-strong"
594	            onClick={() => {
595	              onPersistProperty('cropMinMm', '');
596	              onPersistProperty('cropMaxMm', '');
597	              setCropDraft({ minX: '', minY: '', maxX: '', maxY: '' });
598	            }}
599	          >
600	            {pv('clearCrop')}
601	          </button>
602	        </div>
603	      </div>
604	
605	      <div className="border-t border-border pt-2 space-y-2">
606	        <div className="font-semibold text-muted">{pv('viewRange')}</div>
607	        {(
608	          [
609	            { key: 'viewRangeBottomMm', label: pv('rangeBottom'), val: el.viewRangeBottomMm },
610	            { key: 'viewRangeTopMm', label: pv('rangeTop'), val: el.viewRangeTopMm },
611	            { key: 'cutPlaneOffsetMm', label: pv('cutPlaneOffset'), val: el.cutPlaneOffsetMm },
612	          ] as { key: string; label: string; val: number | null | undefined }[]
613	        ).map(({ key, label, val }) => (
614	          <label key={key} className={LABEL_CLS}>
615	            {label}
616	            <input
617	              className={INPUT_CLS}
618	              defaultValue={val == null ? '' : String(val)}
619	              key={`${key}-${el.id}-${val ?? 'null'}-${revision}`}
620	              placeholder={pv('emptyClearsPlaceholder')}
621	              inputMode="decimal"
622	              onBlur={(e) => onPersistProperty(key, e.target.value.trim())}
623	            />
624	          </label>
625	        ))}
626	      </div>
627	    </div>
628	  );
629	}
