730	  onSave: (baseFamilyId: string, name: string, params: Record<string, unknown>) => void;
731	  onCancel: () => void;
732	}): JSX.Element {
733	  const families = BUILT_IN_FAMILIES.filter((f) => f.discipline === discipline);
734	  const [baseFamilyId, setBaseFamilyId] = useState(families[0]?.id ?? '');
735	  const [name, setName] = useState('');
736	  const [paramDraft, setParamDraft] = useState<Record<string, string>>({});
737	
738	  const baseFam = getFamilyById(baseFamilyId);
739	  const lengthParams = baseFam?.params.filter((p) => p.type === 'length_mm') ?? [];
740	
741	  function handleSave(): void {
742	    const params: Record<string, unknown> = { name: name.trim(), baseFamilyId };
743	    for (const p of lengthParams) {
744	      const raw = paramDraft[p.key];
745	      const val = raw !== undefined ? Number(raw) : (p.default as number);
746	      if (Number.isFinite(val)) params[p.key] = val;
747	    }
748	    onSave(baseFamilyId, name.trim(), params);
749	  }
750	
751	  return (
752	    <div className="mt-1 space-y-1.5 rounded border border-border bg-background p-2">
753	      <label className={LABEL_CLS}>
754	        Base family
755	        <select
756	          className={INPUT_CLS}
757	          value={baseFamilyId}
758	          onChange={(e) => {
759	            setBaseFamilyId(e.target.value);
760	            setParamDraft({});
761	          }}
762	        >
763	          {families.map((f) => (
764	            <option key={f.id} value={f.id}>
765	              {f.name}
766	            </option>
767	          ))}
768	        </select>
769	      </label>
770	      <label className={LABEL_CLS}>
771	        Type name
772	        <input
773	          className={INPUT_CLS}
774	          value={name}
775	          onChange={(e) => setName(e.target.value)}
776	          placeholder="e.g. Wide fire door"
777	          autoFocus
778	        />
779	      </label>
780	      {lengthParams.map((p) => (
781	        <label key={p.key} className={LABEL_CLS}>
782	          {p.label} (mm)
783	          <input
784	            className={INPUT_CLS}
785	            type="number"
786	            value={paramDraft[p.key] ?? String(p.default as number)}
787	            onChange={(e) => setParamDraft((d) => ({ ...d, [p.key]: e.target.value }))}
788	          />
789	        </label>
790	      ))}
791	      <div className="flex gap-2 pt-0.5">
792	        <button
793	          type="button"
794	          disabled={!name.trim()}
795	          onClick={handleSave}
796	          className="flex-1 rounded border border-border bg-surface-strong px-2 py-0.5 text-[10px] hover:bg-accent-soft disabled:opacity-40"
797	        >
798	          Save type
799	        </button>
800	        <button
801	          type="button"
802	          onClick={onCancel}
803	          className="rounded border border-border px-2 py-0.5 text-[10px] hover:bg-surface-strong"
804	        >
805	          Cancel
806	        </button>
807	      </div>
808	    </div>
809	  );
810	}
